  "marin-stinson-e": { description: "Urban Electric Comfort E-Bike · 27.5\" · S/M/L/XL. Marin's renowned Stinson comfort bike, now with a boost. Smooth 250W rear hub motor, integrated 340Wh in-tube battery, and a torque-sensing BB that makes power feel natural. Upright, relaxed, and effortlessly electric — built for bike paths and daily commuting.", specs: {"Frame": "Series 1 Comfort, E-Bike Specific, 6061 Aluminum, 27.5\", Comfort Control Geometry, Fender/Rack/Kickstand Mounts", "Motor": "Bafang 250W Rear Hub, 40Nm torque, Class 1 (20mph/32km/h)", "Battery": "Bafang 340Wh, 36V, Integrated In-Tube", "Range": "15–62 miles (25–100 km) depending on mode/terrain", "Drivetrain": "Shimano Acera 8-speed, SunRace 11-34T cassette, 38T chainring", "Brakes": "Tektro MDM280 Mechanical Disc, 160mm rotors (F/R)", "Tires": "Vee Speedster 27.5” × 2.35”, Puncture Protection", "Display": "Handlebar LCD; Bafang Go App compatible"}, images: ["https://marinbikes.com/cdn/shop/files/2025_MARIN_STINSON_E_BLACK_SIDE_1.png?v=1753862906&width=1000","https://marinbikes.com/cdn/shop/files/2025_MARIN_STINSON_E_SILVER_SIDE_52da63a1-edc3-401a-a329-2405e10cfb54.png?v=1755715647&width=1000","https://marinbikes.com/cdn/shop/files/2025_MARIN_STINSON_E_HANDLEBAR_CONTROL.jpg?v=1755715647&width=1000","https://marinbikes.com/cdn/shop/files/2025_MARIN_STINSON_E_DERAILLEUR.jpg?v=1755715003&width=1000"] },
